const value = Number(msg.payload.manager_power) || 0;  

let payload = msg.payload; // bestaande payload onthouden

if (value < 0) {
    payload.gridInputPower = value *-1;
    payload.outputHomePower = 0;
} else {
    payload.outputHomePower = value;
    payload.gridInputPower = 0;
}

msg.payload = payload;
return msg;

